  const sideTop: TopoId[] = [];
  const sideLeft: TopoId[] = [];
  const capBot: TopoId[] = [];
  const capTop: TopoId[] = [];
  const sideFace: TopoId[] = [];
  const sideLoop: TopoId[] = [];
  const eBot: TopoId[] = [];
  const eTop: TopoId[] = [];
  const eVert: TopoId[] = [];
  for (let i = 0; i < n; i++) {
    sideBottom.push(mint());
    sideRight.push(mint());
    sideTop.push(mint());
    sideLeft.push(mint());
    capBot.push(mint());
    capTop.push(mint());
    sideFace.push(mint());
    sideLoop.push(mint());
