    expect(caps.map((s) => (s.gen.role === 'cap' ? s.gen.end : '')).sort()).toEqual(['end', 'start']);
    expect(sides.map((s) => (s.gen.role === 'side' ? s.gen.curve : '')).sort()).toEqual([
