        if (this.disposed) return;
        this.renderer.render(this.scene, this.cameraState.camera);
      });
    }

    dispose(): void {
      this.disposed = true;
      this.resizeObserver.disconnect();
      this.cameraState.dispose();
      this.renderer.dispose();
      this.renderer.domElement.remove();
      this.overlay.remove();
    }
  }
