    const caps = rd.mesh.faceSpans.filter((s) => s.gen.role === 'cap');
    const sides = rd.mesh.faceSpans.filter((s) => s.gen.role === 'side');
    expect(caps.map((s) => (s.gen.role === 'cap' ? s.gen.end : '')).sort()).toEqual(['end', 'start']);
