    // Bounding box of the mesh: [0,4] x [0,3] x [0,5].
    const min = [Infinity, Infinity, Infinity];
    const max = [-Infinity, -Infinity, -Infinity];
    for (let i = 0; i < rd.mesh.positions.length; i += 3) {
      for (let k = 0; k < 3; k++) {
        min[k] = Math.min(min[k]!, rd.mesh.positions[i + k]!);
