  // --- 4. caps ---
  // Bottom: outward normal is -plane.z; swapping x/y gives z = x cross y = plane.y x plane.x = -plane.z.
  const botCs: PlaneCS = { origin: plane.origin, x: plane.y, y: plane.x, z: scale3(plane.z, -1) };
